Cooldown presets to offer later: 20 minutes (1200), 24 hours (86400), 72 hours (259200), 30 days (2592000).

Create **`LogUrgeView.swift`**:

```swift
import SwiftUI
import SwiftData

struct LogUrgeView: View {
    @Environment(\.modelContext) private var context
    @Environment(\.dismiss) private var dismiss

    @State private var itemName = ""
    @State private var price = ""
    @State private var link = ""
    @State private var reason = ""
    @State private var wantLevel = 5.0
    @State private var cooldown: Double = 86_400

    private let presets: [(String, Double)] = [
        ("20 minutes", 1_200), ("24 hours", 86_400),
        ("72 hours", 259_200), ("30 days", 2_592_000)
    ]

    var body: some View {
        NavigationStack {
            Form {
                Section("What do you want?") {
                    TextField("Item", text: $itemName)
                    TextField("Price", text: $price).keyboardType(.decimalPad)
                    TextField("Link (optional)", text: $link).textInputAutocapitalization(.never)
                }
                Section("Why do you want it?") {
                    TextField("Write it out. Future you reads this.", text: $reason, axis: .vertical)
                        .lineLimit(3...6)
                    VStack(alignment: .leading) {
                        Text("How badly, right now: \(Int(wantLevel))/10")
                        Slider(value: $wantLevel, in: 1...10, step: 1)
                    }
                }
                Section("Wait how long?") {
                    Picker("Cooldown", selection: $cooldown) {
                        ForEach(presets, id: \.1) { Text($0.0).tag($0.1) }
                    }.pickerStyle(.segmented)
                }
            }
            .navigationTitle("Log an urge")
            .toolbar {
                ToolbarItem(placement: .confirmationAction) {
                    Button("Start timer") { save() }
                        .disabled(itemName.trimmingCharacters(in: .whitespaces).isEmpty)
                }
                ToolbarItem(placement: .cancellationAction) {
                    Button("Cancel") { dismiss() }
                }
            }
        }
    }

    private func save() {
        let urge = Urge(
            itemName: itemName.trimmingCharacters(in: .whitespaces),
            price: Double(price) ?? 0,
            link: link, reason: reason,
            wantLevel: Int(wantLevel),
            cooldownSeconds: cooldown
        )
        context.insert(urge)
        try? context.save()

        // Copy out plain values before the Task — never hand a SwiftData model
        // to another concurrency context. (Added in step 7; comment out for now.)
        let id = urge.id, name = urge.itemName, why = urge.reason
        let level = urge.wantLevel, readyAt = urge.readyAt
        Task {
            await Notifier.schedule(id: id, itemName: name, reason: why,
                                    wantLevel: level, readyAt: readyAt)
        }
        dismiss()
    }
}
```

Comment out the `Task { ... }` block for now — you'll add `Notifier` in step 7 and uncomment it then.

Create **`RootView.swift`** — the app's home screen:

```swift
import SwiftUI
import SwiftData

struct RootView: View {
    @Environment(\.modelContext) private var context
    @Query(sort: \Urge.createdAt, order: .reverse) private var urges: [Urge]
    @State private var showingLog = false
    @State private var deciding: Urge?

    private var waiting: [Urge] { urges.filter(\.isWaiting) }
    private var ripe: [Urge]    { urges.filter(\.isRipe) }

    var body: some View {
        NavigationStack {
            List {
                if !ripe.isEmpty {
                    Section("Time's up — decide") {
                        ForEach(ripe) { urge in
                            Button { deciding = urge } label: {
                                HStack {
                                    VStack(alignment: .leading) {
                                        Text(urge.itemName).font(.headline)
                                        Text("Still want it?").foregroundStyle(.secondary)
                                    }
                                    Spacer()
                                    Image(systemName: "chevron.right")
                                }
                            }
                        }
                    }
                }

                Section("Cooling off") {
                    if waiting.isEmpty {
                        ContentUnavailableView("Nothing on ice",
                            systemImage: "hourglass",
                            description: Text("Next time you want to buy something, log it here first."))
                    }
                    ForEach(waiting) { urge in
                        VStack(alignment: .leading, spacing: 4) {
                            HStack {
                                Text(urge.itemName).font(.headline)
                                Spacer()
                                Text(urge.price, format: .currency(code: "USD"))
                                    .foregroundStyle(.secondary)
                            }
                            // Live countdown, no Timer needed:
                            Text(timerInterval: Date.now...urge.readyAt, countsDown: true)
                                .font(.title3.monospacedDigit())
                                .foregroundStyle(.tint)
                        }
                    }
                    .onDelete { idx in
                        for i in idx { context.delete(waiting[i]) }
                    }
                }
            }
            .navigationTitle("Second Thought")
            .toolbar {
                ToolbarItem(placement: .primaryAction) {
                    Button("Log an urge", systemImage: "plus") { showingLog = true }
                }
            }
            .sheet(isPresented: $showingLog) { LogUrgeView() }
            .sheet(item: $deciding) { urge in VerdictView(urge: urge) }   // step 8
        }
    }
}
```

`@Query` re-runs automatically whenever SwiftData changes, so the list updates the instant you save the form. Comment out the `.sheet(item: $deciding)` line until you build VerdictView in step 8. (`.sheet(item:)` needs `Urge` to be Identifiable — it already is, for free, because every `@Model` conforms to `PersistentModel`.)

Create **`Notifier.swift`**:

```swift
import Foundation
import UserNotifications

enum Notifier {
    static let categoryID = "URGE_READY"
    static let stillWantID = "STILL_WANT"
    static let letGoID = "LET_GO"

    /// Registers the two buttons that appear when you long-press the notification.
    static func configureCategories() {
        let still = UNNotificationAction(identifier: stillWantID,
                                         title: "I still want it", options: [.foreground])
        let letGo = UNNotificationAction(identifier: letGoID,
                                         title: "Let it go", options: [.destructive])
        let category = UNNotificationCategory(identifier: categoryID,
                                              actions: [still, letGo],
                                              intentIdentifiers: [])
        UNUserNotificationCenter.current().setNotificationCategories([category])
    }

    @discardableResult
    static func requestPermission() async -> Bool {
        (try? await UNUserNotificationCenter.current()
            .requestAuthorization(options: [.alert, .sound, .badge])) ?? false
    }

    /// Takes plain values, not the Urge object — see 'why this matters' below.
    static func schedule(id: UUID, itemName: String, reason: String,
                         wantLevel: Int, readyAt: Date) async {
        let content = UNMutableNotificationContent()
        content.title = "Still want the \(itemName)?"
        content.body = reason.isEmpty
            ? "You rated this \(wantLevel)/10. Do you still need it?"
            : "You said: \u{201C}\(reason)\u{201D} — do you still need it?"
        content.sound = .default
        content.categoryIdentifier = categoryID
        content.userInfo = ["urgeID": id.uuidString]

        let seconds = max(1, readyAt.timeIntervalSinceNow)
        let trigger = UNTimeIntervalNotificationTrigger(timeInterval: seconds, repeats: false)
        let request = UNNotificationRequest(identifier: id.uuidString,
                                            content: content, trigger: trigger)
        try? await UNUserNotificationCenter.current().add(request)
    }

    /// Cancel if the user decides early or deletes the urge.
    static func cancel(id: UUID) {
        UNUserNotificationCenter.current()
            .removePendingNotificationRequests(withIdentifiers: [id.uuidString])
    }
}
```

Ask for permission once, at launch. In `SecondThoughtApp.swift`:

```swift
WindowGroup {
    RootView()
        .task {
            Notifier.configureCategories()
            await Notifier.requestPermission()
        }
}
.modelContainer(for: Urge.self)
```

Now uncomment the `Task { await Notifier.schedule(...) }` block in `LogUrgeView.save()`.

Also cancel the pending notification when an urge is swiped away — in `RootView`'s `.onDelete`:

```swift
.onDelete { idx in
    for i in idx {
        Notifier.cancel(id: waiting[i].id)
        context.delete(waiting[i])
    }
}
```

Run the app. **iOS will show a permission alert — you must tap "Allow".** If you tap "Don't Allow", no notification will ever fire and the app will look broken. (Reset it any time with: Simulator > Device > Erase All Content and Settings.)

Create **`VerdictView.swift`**:

```swift
import SwiftUI
import SwiftData

struct VerdictView: View {
    @Environment(\.modelContext) private var context
    @Environment(\.dismiss) private var dismiss
    let urge: Urge

    var body: some View {
        NavigationStack {
            VStack(spacing: 24) {
                Spacer()
                Text("Do you still need\n\(urge.itemName)?")
                    .font(.largeTitle.bold())
                    .multilineTextAlignment(.center)

                VStack(spacing: 8) {
                    Text("\(urge.createdAt, style: .relative) ago you said:")
                    if !urge.reason.isEmpty {
                        Text("\u{201C}\(urge.reason)\u{201D}")
                            .italic()
                            .multilineTextAlignment(.center)
                    }
                    Text("You wanted it \(urge.wantLevel)/10.")
                        .foregroundStyle(.secondary)
                }
                .font(.callout)
                .padding(.horizontal)

                Spacer()

                Button {
                    resolve(.skipped)
                } label: {
                    Label("No — let it go", systemImage: "wind")
                        .frame(maxWidth: .infinity)
                }
                .buttonStyle(.borderedProminent)
                .controlSize(.large)

                Button("Yes, I still want it") { resolve(.bought) }
                    .buttonStyle(.bordered)
                    .controlSize(.large)
                    .frame(maxWidth: .infinity)

                Text("Saying yes is allowed. The point was to decide on purpose.")
                    .font(.footnote)
                    .foregroundStyle(.secondary)
            }
            .padding()
            .navigationTitle(urge.price.formatted(.currency(code: "USD")))
            .navigationBarTitleDisplayMode(.inline)
        }
    }

    private func resolve(_ verdict: Verdict) {
        urge.verdict = verdict
        urge.decidedAt = .now
        try? context.save()
        Notifier.cancel(id: urge.id)
        dismiss()
    }
}
```

Uncomment the `.sheet(item: $deciding)` line in RootView.

**Optional but great:** make tapping the notification open straight into this screen. Add a delegate in `SecondThoughtApp.swift` that conforms to `UNUserNotificationCenterDelegate`, implements `userNotificationCenter(_:didReceive:)`, reads `response.notification.request.content.userInfo["urgeID"]`, and publishes it to an `@Observable` router that RootView watches to set `deciding`. Also implement `willPresent` returning `[.banner, .sound]` so notifications show even while the app is open.

Create **`StatsView.swift`** and add it as a second tab (wrap RootView and StatsView in a `TabView`):

```swift
import SwiftUI
import SwiftData

struct StatsView: View {
    @Query private var urges: [Urge]

    private var skipped: [Urge] { urges.filter { $0.verdict == .skipped } }
    private var bought: [Urge]  { urges.filter { $0.verdict == .bought } }
    private var saved: Double   { skipped.reduce(0) { $0 + $1.price } }
    private var resistRate: Double {
        let decided = skipped.count + bought.count
        return decided == 0 ? 0 : Double(skipped.count) / Double(decided)
    }

    var body: some View {
        NavigationStack {
            List {
                Section {
                    VStack(spacing: 4) {
                        Text(saved, format: .currency(code: "USD"))
                            .font(.system(size: 44, weight: .bold, design: .rounded))
                            .contentTransition(.numericText())
                        Text("not spent").foregroundStyle(.secondary)
                    }
                    .frame(maxWidth: .infinity)
                    .padding(.vertical, 8)
                }
                Section("Track record") {
                    LabeledContent("Urges resisted", value: "\(skipped.count)")
                    LabeledContent("Bought anyway", value: "\(bought.count)")
                    LabeledContent("Resist rate", value: resistRate.formatted(.percent.precision(.fractionLength(0))))
                }
                Section("Let go") {
                    ForEach(skipped) { urge in
                        LabeledContent(urge.itemName,
                                       value: urge.price.formatted(.currency(code: "USD")))
                    }
                }
            }
            .navigationTitle("Saved")
        }
    }
}
```

Now wire both screens together in `SecondThoughtApp.swift` — this is the finished app entry point:

```swift
import SwiftUI
import SwiftData

@main
struct SecondThoughtApp: App {
    var body: some Scene {
        WindowGroup {
            TabView {
                RootView()
                    .tabItem { Label("Waiting", systemImage: "hourglass") }
                StatsView()
                    .tabItem { Label("Saved", systemImage: "banknote") }
            }
            .task {
                Notifier.configureCategories()
                await Notifier.requestPermission()
            }
        }
        .modelContainer(for: Urge.self)
    }
}
